sp_widget.client_script:
function ($scope, spUtil) {
	var c = this;
	if (!c.options.table)
		return;

	spUtil.recordWatch($scope, c.options.table, c.options.filter);
}

sp_widget.css:
/* ── MAIN CARD CONTAINER ── */
.smartcare-count-card {
  background: #ffffff !important;
  border-radius: 20px;
  padding: 24px;
  border: 1px solid #f1f5f9;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.04);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  margin-bottom: 20px;
}

.smartcare-count-card:hover {
  transform: translateY(-5px);
  box-shadow: 0 15px 35px rgba(99, 102, 241, 0.1);
  border-color: #e2e8f0;
}

/* ── LAYOUT ── */
.smartcare-count-card .card-link {
  text-decoration: none !important;
  display: block;
}

.smartcare-count-card .card-content {
  display: flex;
  align-items: center;
  gap: 20px;
}

/* ── ICON STYLING ── */
.smartcare-count-card .icon-box {
  width: 52px;
  height: 52px;
  background: #f5f3ff; /* Soft Blush/Indigo tint */
  border-radius: 14px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: 0.2s;
}

.smartcare-count-card .icon-box i {
  color: #6366f1; /* Indigo */
  font-size: 22px;
}

.smartcare-count-card:hover .icon-box {
  background: #6366f1;
}

.smartcare-count-card:hover .icon-box i {
  color: #ffffff;
}

/* ── DATA STYLING ── */
.smartcare-count-card .data-section {
  flex: 1;
}

.smartcare-count-card .count-value {
  font-size: 36px;
  font-weight: 800;
  color: #1e293b;
  line-height: 1;
  margin-bottom: 4px;
  font-family: 'Inter', sans-serif;
}

.smartcare-count-card .count-title {
  font-size: 11px;
  font-weight: 700;
  color: #94a3b8;
  text-transform: uppercase;
  letter-spacing: 1px;
}

sp_widget.script:
(function() {
	if (!options.table)
		return;

	// Default filter if none provided
	data.filter = options.filter || 'sys_id!=NULL';

	// Standard Scoped GlideRecord
	var gr = new GlideRecord(options.table);
	gr.addEncodedQuery(data.filter);
	gr.query();

	// Get the total number of records
	data.count = gr.getRowCount();	
})();
